import React, { FunctionComponent } from 'react';
import { NavLink } from 'react-router-dom';
import Icon from '../../../styles/fonts/Icons';
import './Navbar.scss';

interface INavbarProps {
}

export const Navbar: FunctionComponent<INavbarProps> = (props) => {
  return (
    <nav className='navbar__container box__blured'>
      <div className="navbar__mobile-options">
        <Icon className='icon' icon='menu' size={27} />
      </div>
      <div className="navbar__settings">
        <Icon className='icon' icon='settings' size={23} />
        <Icon className='icon' icon='mail' size={23} />
      </div>
      <ul className='navbar__list'>
        <li>
          <NavLink to='/'>
            Home
          </NavLink>
          </li>
        <li>
          <NavLink to='/work'>
            Projects
            </NavLink>
        </li>
        <li>
          <NavLink to='/about'>
            About
          </NavLink></li>
      </ul>
      <div className="navbar__social">
        <Icon className='icon' icon='linkedin' size={23} />
        <Icon className='icon' icon='facebook' size={23} />
        <Icon className='icon' icon='github' size={23} />
      </div>
    </nav>
  );
};
