import React, { FunctionComponent, useEffect } from 'react';
import gsap from 'gsap';
import ScrollTrigger from 'gsap/ScrollTrigger';
import './Home.scss';

import { GreatWork } from './GreatWork/GreatWork';

interface IHomeProps {
}

export const Home: FunctionComponent<IHomeProps> = (props) => {

  gsap.registerPlugin(ScrollTrigger);
  let tl: gsap.core.Timeline;
  
  useEffect(() => {
    handleInitScroll();
    return () => {
      tl.kill();
    };
  }, []);

  const handleInitScroll = () => {
    const initCard = document.querySelector('.home__container .init-card');
    const shard1 = document.querySelector('.home__container .shard-1');
    const shard2 = document.querySelector('.home__container .shard-2');
    const shard3 = document.querySelector('.home__container .shard-3');
    const shard4 = document.querySelector('.home__container .shard-4');
    const shard5 = document.querySelector('.home__container .shard-5');
    const backdropCircle = document.querySelector('.home__container .backdrop-circle');
    tl = gsap.timeline({
      scrollTrigger: {
        trigger: '.home__container',
        markers: true,
        start: 'top top',
        end: 'bottom bottom',
        scrub: true,
        pinSpacing: false
      }
    });
    tl.to(initCard, { top: '50vh', duration: 3});
    tl.to(shard1, { top: '125vh', left: '-30vw', scale: 0.8, rotate: 245, duration: 3}, '-=3');
    tl.to(shard2, { top: '10vh', left: '-10vw', scale: 2.5, rotate: -90, duration: 3}, '-=3');
    tl.to(shard3, { top: '10vh', left: '45vw', scale: 1.5, rotate: 180, duration: 3}, '-=3');
    tl.to(shard4, { top: '130vh', left: '105vw', scale: 1.3, rotate: -180, duration: 3}, '-=3');
    tl.to(shard5, { top: '70vh', left: '-20vw', scale: 1.5, rotate: -340, duration: 3}, '-=3');
    tl.to(backdropCircle, { top: '-50vh', left: '30vw', scale: 3.5, opacity: 0, duration: 3 }, '-=3');
  };

  return (
    <>
      <section className='home__container'>
        <div className="animated-backdrop">
          <div className="init-card box__shadow box__blured">
            <p> XENOCIDE </p>
            <p> Creative frontend developer and illustrator </p>
          </div>
          <div className='backdrop-circle'></div>
          <img src="./assets/home/shards/shard-1.svg" alt="" className="shard-1" />
          <img src="./assets/home/shards/shard-2.svg" alt="" className="shard-2" />
          <img src="./assets/home/shards/shard-3.svg" alt="" className="shard-3" />
          <img src="./assets/home/shards/shard-4.svg" alt="" className="shard-4" />
          <img src="./assets/home/shards/shard-5.svg" alt="" className="shard-5" />
        </div>
      </section>
      <GreatWork />
    </>
  );
};