import { createSlice } from "@reduxjs/toolkit"

const initialState = {
  redux: false
}

export const uiSlice = createSlice({
  name: 'ui',
  initialState,
  reducers: {
    // reduxSuccess: (state, action) => {}
    reduxSuccess: (state) => {
      state.redux = true;
    }
  }
});

export const {
  reduxSuccess
} = uiSlice.actions;

export default uiSlice.reducer;