import gsap from 'gsap';

export const handleInitRoomLighting = (tl: gsap.core.Timeline, timeRate: number) => {
  const layerLight1Bg = document.querySelector('.great-work__container .office-wrapper.light .layer-1 .bg');
  const layerLight1Clouds = document.querySelector('.great-work__container .office-wrapper.light .layer-1 .clouds');
  const layerLight1Plant = document.querySelector('.great-work__container .office-wrapper .layer-1 .plant-wrapper.light');
  const layerLight2Pc = document.querySelector('.great-work__container .office-wrapper .layer-2 .pc.light');
  const layerLight2Plant10 = document.querySelector('.great-work__container .office-wrapper .layer-2 .plant-10-wrapper.light');
  const layerLight2CupFull = document.querySelector('.great-work__container .office-wrapper .layer-2 .cup-full.light');
  const layerLight3 = document.querySelector('.great-work__container .office-wrapper .layer-2 .layer-3.light');
  const lightElements = [
    layerLight1Bg,
    layerLight1Clouds,
    layerLight1Plant,
    layerLight2Pc,
    layerLight2Plant10,
    layerLight2CupFull,
    layerLight3
  ];
  tl.to(lightElements, { opacity: 0, duration: timeRate, delay: 15 }, 0)
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.9) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.8) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.7) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.6) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.5) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.4) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.3) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.3) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.2) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.3) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.4) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.5) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.6) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.7) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 0.8) })
    .to(lightElements, { opacity: 0, duration: (timeRate * 0.9) })
    .to(lightElements, { opacity: 1, duration: (timeRate * 2) });
};

export const handleInitSunAndMoon = (tl: gsap.core.Timeline, timeRate: number) => {
  const layerLight1Sun = document.querySelector('.great-work__container .office-wrapper.light .layer-1 .sun');
  const layerLight1Moon = document.querySelector('.great-work__container .office-wrapper.light .layer-1 .moon');
  tl.fromTo(layerLight1Sun, { opacity: 1 }, { opacity: 1, x: 0, y: 0 }, 0)
    .to(layerLight1Sun, { x: 60, y: -33, duration: timeRate }, 0).add('cp', timeRate)
    .to(layerLight1Sun, { opacity: 0, duration: timeRate }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.9) }, `cp`).add('cp', `cp+=${ timeRate * 0.9 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.8) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.8) }, `cp`).add('cp', `cp+=${ timeRate * 0.8 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.7) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.7) }, `cp`).add('cp', `cp+=${ timeRate * 0.7 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.6) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.6) }, `cp`).add('cp', `cp+=${ timeRate * 0.6 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.5) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.6) }, `cp`).add('cp', `cp+=${ timeRate * 0.6 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.5) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.5) }, `cp`).add('cp', `cp+=${ timeRate * 0.5 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.4) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.4) }, `cp`).add('cp', `cp+=${ timeRate * 0.4 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.3) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.4) }, `cp`).add('cp', `cp+=${ timeRate * 0.4 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.3) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.3) }, `cp`).add('cp', `cp+=${ timeRate * 0.3 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.2) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.16) }, `cp`).add('cp', `cp+=${ timeRate * 0.16 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.13) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.2) }, `cp`).add('cp', `cp+=${ timeRate * 0.2 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.1) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.5) }, `cp`).add('cp', `cp+=${ timeRate * 0.5 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.4) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.5) }, `cp`).add('cp', `cp+=${ timeRate * 0.5 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.4) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.6) }, `cp`).add('cp', `cp+=${ timeRate * 0.6 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.5) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.7) }, `cp`).add('cp', `cp+=${ timeRate * 0.7 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.6) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 0.8) }, `cp`).add('cp', `cp+=${ timeRate * 0.8 }`)
    .to(layerLight1Sun, { opacity: 0, duration: (timeRate * 0.7) }, 'cp')
    .fromTo(layerLight1Moon, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Moon, { opacity: 1, x: 65, y: -37, duration: (timeRate * 0.9) }, `cp`).add('cp', `cp+=${ timeRate * 0.9 }`)
    .to(layerLight1Moon, { opacity: 0, duration: (timeRate * 0.8) }, 'cp')
    .fromTo(layerLight1Sun, { opacity: 0 }, { opacity: 1, x: 0, y: 0 }, 'cp')
    .to(layerLight1Sun, { opacity: 1, x: 60, y: -33, duration: (timeRate * 1) }, `cp`).add('cp', `cp+=${ timeRate * 1 }`)
    .to(layerLight1Sun, { opacity: 1, duration: 30 }, 'cp');
};